  governing_guidelines = 'Migrant and Seasonal Agricultural Worker Protection Act (MSPA), 29 USC 1801-1872; 29 CFR Part 500 (MSPA Regulations); California Labor Code 1682-1699 (Farm Labor Contractor Act); Cal. Lab. Code 1683 (license requirement); Cal. Lab. Code 1684 (conditions for issuance); Cal. Lab. Code 1695 (licensee obligations); Cal. Lab. Code 1695.7 (pre-contract disclosure to growers)',
