  standards_of_creation = 'USDA VS Form 1-27 (Certificate of Veterinary Inspection) signed by accredited veterinarian; health examination within required timeframe (30 days for most states); disease test results per destination state requirements (brucellosis, tuberculosis, trichomoniasis); official individual animal identification (ear tag, brand, or electronic ID per ADT rule); entry permit number from destination state (where required); vaccination records (brucellosis calfhood vaccination documentation)',
  soc_controls = 'USDA-accredited veterinarian signing authority verified before CVI acceptance; state veterinarian endorsement required for export shipments; disease test laboratory NAHLN accreditation or state approval; separation of testing from certification authority; USDA APHIS oversight of accredited veterinarian program (spot audits, renewal requirements); destination state import permit verification; animal identification verification against CVI at destination; accredited veterinarian continuing education requirements'
WHERE name = 'Cattle Health Certificate Officer (Interstate/International)';

UPDATE citizen_catalog SET
  governing_guidelines = '9 CFR Part 89 (Statement of Policy — humane transport); 49 USC 80502 (Twenty-Eight Hour Law); FMCSA Hours of Service 49 CFR Part 395 (agricultural exemptions under 49 CFR 395.1(k)); 9 CFR Part 71.1-71.22 (general requirements for interstate transport); state brand inspection requirements for transport; DOT vehicle safety standards 49 CFR Parts 390-399',
  standards_of_creation = 'Bill of lading or shipping manifest with animal count and description; health certificate (USDA VS Form 1-27) accompanying shipment; brand inspection certificate from origin state; 28-hour unloading documentation (feed, water, rest per 49 USC 80502); vehicle condition and cleanliness records; loading density documentation per species and weight; FMCSA agricultural exemption documentation (150 air-mile radius or seasonal); driver qualification records',
  soc_controls = '28-hour rest, feed, and water documentation with time-stamped records; vehicle inspection before loading for animal safety; driver compliance with HOS agricultural exemptions documented; separation of loading authority from transport authority; APHIS transit documentation verification at destination; brand inspection clearance before departure; vehicle biosecurity decontamination between loads where required; incident and injury reporting during transport'
WHERE name = 'Livestock Transportation Compliance Officer';

UPDATE citizen_catalog SET
  governing_guidelines = 'Packers and Stockyards Act, 7 USC 181-229c; 9 CFR Part 201 (Packers and Stockyards Regulations); 7 USC 228b (prompt payment requirements — by close of next business day); Cal. Food & Agric. Code 21741-21755 (brand inspection at salesyards); USDA AMS Packers and Stockyards Division enforcement',
  standards_of_creation = 'Stockyard registration with USDA AMS; market agency or dealer bond filed per 9 CFR 201.29; sales records per head including seller, buyer, price, weight, and date; prompt payment documentation (payment by close of next business day per 7 USC 228b); brand inspection clearance before sale; custodial account records (trust account for sale proceeds); annual report to USDA; scale ticket documentation',
  soc_controls = 'P&S Division registration and bonding verification; custodial account separation from operating funds per 9 CFR 201.42; prompt payment compliance monitoring (next business day after sale); brand inspection completed before ownership transfer; independent weighing by bonded weigher; USDA compliance audit authority (announced and unannounced); scale testing and certification records; market agency annual financial reporting to USDA'
WHERE name = 'Livestock Auction Compliance Specialist';

