UPDATE citizen_catalog SET
  governing_guidelines = 'Clean Water Act 33 USC 1342 (NPDES Permits for point source discharge); 40 CFR Part 122.23 (Concentrated Animal Feeding Operations — CAFO definition and permitting); 40 CFR Part 412 (CAFO Effluent Guidelines); California Regional Water Board General Orders for CAFOs; Cal. Water Code 13260 (waste discharge requirements); EPCRA 42 USC 11001 (emergency release reporting for ammonia/hydrogen sulfide)',
  standards_of_creation = 'NPDES permit application or Notice of Intent for General Permit; Nutrient Management Plan (NMP) certified by qualified nutrient management planner; annual report filed with permitting authority; runoff and discharge monitoring records per permit conditions; manure storage and land application records with dates, rates, and fields; mortality disposal records; facility design documentation meeting permit specifications; best management practices (BMP) documentation',
  soc_controls = 'EPA or state permit issuance authority separate from facility operation; annual NMP certification by qualified professional (P.E., CCA, or state-certified planner); discharge monitoring reports filed with regulatory board per permit schedule; separation of environmental monitoring from compliance reporting; third-party inspection authority by state water board; off-site manure transfer documentation; emergency response plan for catastrophic discharge; permit modification tracking when herd size changes'
WHERE name = 'Feedlot / CAFO Permit Specialist';

UPDATE citizen_catalog SET
  governing_guidelines = 'Taylor Grazing Act, 43 USC 315-315r; Federal Land Policy and Management Act (FLPMA), 43 USC 1701-1787; 43 CFR Part 4100 (BLM Grazing Administration); 36 CFR Part 222 (Forest Service Range Management); National Environmental Policy Act (NEPA) 42 USC 4321 et seq.; Endangered Species Act 16 USC 1531-1544 (consultation for listed species on allotments)',
  standards_of_creation = 'Grazing permit or lease application with BLM or Forest Service; allotment management plan (AMP) developed cooperatively; NEPA environmental assessment or impact statement; Annual Operating Instructions (AOI) specifying season of use and AUMs; actual use reports filed after grazing season; range improvement permits and cost-share agreements; permit transfer documentation with agency approval; trespass documentation where unauthorized use occurs',
  soc_controls = 'BLM or Forest Service resource specialist range monitoring (utilization studies, trend monitoring); NEPA compliance completed before permit issuance or renewal; annual authorized use calculation (AUMs) based on rangeland conditions; separation of permit issuance authority from range monitoring; public participation in allotment management planning; permit non-transferability without agency approval; rangeland health assessment per BLM Standards and Guidelines; ESA Section 7 consultation documentation for allotments with listed species'
WHERE name = 'Grazing Permit Specialist (Federal Lands)';

UPDATE citizen_catalog SET
  governing_guidelines = '9 CFR Part 79 (Scrapie in Sheep and Goats); National Scrapie Eradication Program (NSEP); Scrapie Free Flock Certification Program (SFCP) standards; USDA APHIS Veterinary Services program standards; state scrapie program regulations; Animal Health Protection Act 7 USC 8301-8322',
  standards_of_creation = 'Premises identification number (PIN) registration with USDA; official individual animal identification (ear tags per 9 CFR 79.2); interstate movement documentation with official ID; flock status records (enrolled, monitored, complete monitored, export certified); genotype testing records for susceptibility classification; exposed and high-risk animal documentation; flock plan for infected or exposed flocks; SFCP enrollment and maintenance records',
  soc_controls = 'USDA APHIS oversight of flock certification status; accredited veterinarian sample collection for genotype testing; National Veterinary Services Laboratory (NVSL) testing and confirmation; separation of flock status determination from flock management decisions; mandatory reporting of suspect animals to state veterinarian; trace-back investigation authority for positive cases; flock plan compliance monitoring; interstate movement restriction enforcement for non-compliant flocks'
WHERE name = 'Scrapie Program Compliance Officer (Sheep/Goat)';

UPDATE citizen_catalog SET
  governing_guidelines = '9 CFR Parts 145-147 (National Poultry Improvement Plan — NPIP); 9 CFR Part 56 (Control and Indemnity for Avian Influenza); 9 CFR Part 82 (Exotic Newcastle Disease); state poultry health regulations; Animal Health Protection Act 7 USC 8301-8322; USDA APHIS Highly Pathogenic Avian Influenza Response Plan',
  standards_of_creation = 'NPIP flock participation certificate issued by Official State Agency; pullorum-typhoid testing records per 9 CFR 145 (S. pullorum and S. gallinarum); avian influenza monitoring records (H5/H7 testing); flock plan for participating flocks; written biosecurity plan per NPIP Provisions; premises identification; official NPIP testing records with laboratory results; export health documentation per destination country requirements',
  soc_controls = 'NPIP Official State Agency (OSA) oversight and certification authority; authorized laboratory testing by NPIP-approved labs; separation of flock testing from flock classification decisions; USDA APHIS backup authority for disease response; indemnity documentation requirements and payment verification; quarantine authority for suspect or confirmed premises; HPAI rapid response team protocols; biosecurity audit by authorized NPIP personnel'
WHERE name = 'Poultry Flock Health Officer';

UPDATE citizen_catalog SET
  governing_guidelines = '9 CFR Part 71 (general interstate movement requirements); 9 CFR Part 78 (Brucellosis — swine); 9 CFR Part 85 (Pseudorabies); Swine Health Information Center (SHIC) disease monitoring programs; state swine health regulations; Animal Health Protection Act 7 USC 8301-8322; Secure Pork Supply Plan standards',
  standards_of_creation = 'Certificate of Veterinary Inspection (CVI) for interstate movement; herd status documentation (validated brucellosis-free, Stage IV/V pseudorabies); disease test records with laboratory results; movement documentation (origin, destination, number, date); isolation and quarantine records where disease suspected; Secure Pork Supply Plan documentation; premises identification; African Swine Fever surveillance documentation',
  soc_controls = 'Accredited veterinarian testing and certification requirements; state veterinarian herd status validation independent of herd owner; laboratory accreditation through NAHLN; separation of herd status determination from herd management; mandatory disease reporting to state veterinarian within required timeframe; interstate movement pre-approval by destination state; foreign animal disease investigation protocols; Secure Pork Supply Plan site assessment and audit'
