UPDATE citizen_catalog SET
  governing_guidelines = '9 CFR Part 71 (interstate exhibition movement requirements); state fair and exhibition health requirements (varies by state); 3 CCR 751-869 (California livestock exhibition health requirements); local fair board rules and regulations; Cal. Food & Agric. Code 19120-19620 (Fairs and Expositions); state veterinarian exhibition orders',
  standards_of_creation = 'Exhibition health certificate (CVI) issued within required timeframe before exhibition; species-specific test results (coggins for equine, brucellosis for cattle, etc.); official animal identification per exhibition requirements; vaccination records per species and state requirements; veterinary examination at exhibition entry point; release documentation upon departure; exhibition entry forms with owner and animal identification',
  soc_controls = 'Exhibition veterinarian appointed independently from exhibitors; entry inspection completed before commingling with other animals; state veterinarian oversight of exhibition health requirements; quarantine authority at exhibition for suspect animals; documentation retention by fair board per state requirements; separation of exhibition management from health compliance authority; post-exhibition disease surveillance reporting; species isolation requirements enforcement'
