UPDATE citizen_catalog SET
  governing_guidelines = 'Animal Damage Control Act, 7 USC 426-426d; USDA Wildlife Services Directive Series; Cal. Fish & Game Code 4150-4156 (depredation permits); Cal. Food & Agric. Code 6021-6048 (predatory animal control); NEPA compliance for federal Wildlife Services actions; Endangered Species Act 16 USC 1531 (restrictions on control of listed species)',
  standards_of_creation = 'Depredation permit application filed with CDFW; livestock loss documentation (species, number, cause of death determination, date, GPS location); Wildlife Services work initiation document; non-lethal methods documentation attempted before lethal control; take records (species, method, date, location, number); annual program reporting; NEPA compliance records (environmental assessment or categorical exclusion); loss verification by qualified investigator',
  soc_controls = 'Verified livestock loss confirmed before lethal control authorization; Wildlife Services specialist certification and training requirements; separation of loss verification from control action authority; CDFW permit issuance for take of state-listed or protected species; annual program review and environmental compliance; public reporting requirements for Wildlife Services activities; non-lethal method exhaustion documentation; M-44 and other restricted device use reporting'
