UPDATE citizen_catalog SET
  governing_guidelines = 'Cal. Civ. Code 841 (Adjoining Landowners — fencing cost sharing); Cal. Food & Agric. Code 17001-17128 (Fences and Cattle Guards); local fencing ordinances (county-specific requirements); BLM and Forest Service fence standards for grazing allotments; 43 CFR 4120.3-2 (range improvements — fencing on federal lands); Cal. Civ. Code 841.4 (spite fence prohibition)',
  standards_of_creation = 'Fence construction specifications per county or federal standards; boundary survey documentation by licensed surveyor; cost-sharing agreements between adjoining landowners per Cal. Civ. Code 841; wildlife-friendly fence specifications where required (e.g., BLM or CDFW guidelines); right-of-way documentation for fences crossing other property; maintenance records and responsibility allocation; fence viewer reports where applicable; material specifications meeting county or agency standards',
  soc_controls = 'Boundary survey by California-licensed land surveyor before construction; cost-sharing dispute resolution process per Cal. Civ. Code 841; county fence viewer authority where available under local ordinance; separation of boundary determination from fence construction decisions; federal land fence permits approved by BLM or Forest Service; wildlife passage compliance verification; maintenance responsibility documentation signed by both parties; encroachment resolution procedures'
WHERE name = 'Fencing Compliance Specialist';

UPDATE citizen_catalog SET
  governing_guidelines = 'Cal. Food & Agric. Code 9141-9151 (Dead Animal Disposal); Cal. Food & Agric. Code 10901-10981 (Rendering); 3 CCR 1180-1180.15 (disposal methods — burial, composting, incineration); local air quality rules restricting open burning; state water board requirements for groundwater protection near burial sites; USDA APHIS guidelines for disease-related mortality disposal',
  standards_of_creation = 'Mortality records documenting date, species, estimated weight, cause of death if known, and disposal method; rendering company pickup records with dates and quantities; composting facility compliance records (temperature monitoring, turning schedule); burial site documentation (depth, setbacks from water sources, soil type); incinerator permit and operation records; catastrophic mortality disposal plan; disease investigation samples collected before disposal where required',
