WHERE name = 'Livestock Mortality Disposal Specialist';

UPDATE citizen_catalog SET
  governing_guidelines = 'Cal. Civ. Code 1714 (general negligence standard — California has no equine activity liability statute); assumption of risk doctrine per Cal. case law (Knight v. Jewett, 3 Cal.4th 296); Equine Activity Liability Acts in 47 other states; local business licensing requirements for equine facilities; Cal. Civ. Code 1668 (certain releases against public policy); OSHA workplace safety for equine facility employees',
  standards_of_creation = 'Liability waivers and releases drafted per state enforceability requirements; posted warning signs (required in states with EALA); insurance certificates (general liability and equine-specific professional liability); facility inspection records; instructor and guide certification documentation (CHA, ARIA, or equivalent); participant medical disclosure forms; incident and injury reports with witness statements; helmet and safety equipment provision records',
