  governing_guidelines = 'Cal. Penal Code 596.7 (rodeo humane requirements — veterinarian present); local rodeo permit ordinances; PRCA (Professional Rodeo Cowboys Association) Animal Welfare Rules; state humane investigation authority Cal. Penal Code 597 (animal cruelty); insurance and liability requirements per local jurisdiction; Cal. Food & Agric. Code livestock event provisions',
  standards_of_creation = 'Rodeo permit application filed with local jurisdiction; veterinarian-on-site documentation (name, license number, presence certification per Cal. Penal Code 596.7); animal welfare plan specific to events; stock contractor license and insurance; liability insurance certificates meeting local minimum requirements; event-specific safety plan; arena inspection records before each performance; animal injury and incident reports filed within 24 hours',
