UPDATE citizen_catalog SET
  governing_guidelines = 'National Association of Animal Breeders (NAAB) Certified Semen Services (CSS) program standards; 9 CFR Part 98 (Importation of Certain Animal Embryos and Semen); state AI technician licensing requirements (varies by state); breed registry requirements for parentage verification; IETS (International Embryo Technology Society) manual for embryo transfer; USDA APHIS import-export veterinary requirements for genetic material',
  standards_of_creation = 'AI technician certification or license per state requirements; semen collection facility CSS accreditation documentation; semen storage and handling documentation (tank inventories, temperature monitoring); breeding service records (sire identification, dam identification, date, technician name); pregnancy verification records; parentage verification records (DNA testing by approved laboratory); import and export documentation for genetic material per APHIS requirements; semen quality assurance records',
