  governing_guidelines = 'Cal. Food & Agric. Code 32501-39912 (Milk and Milk Products); Cal. Food & Agric. Code 33112 (registered dairy inspector certification); Cal. Food & Agric. Code 33222 (producer permit requirement); Cal. Food & Agric. Code 33257 (dairy farm inspection fee); Cal. Food & Agric. Code 33322 (manufacturing milk inspection); FDA Pasteurized Milk Ordinance (PMO); 21 CFR Part 1240.61 (mandatory pasteurization)',
  standards_of_creation = 'Dairy farm permit issued by CDFA or approved milk inspection service; dairy farm inspection score sheets per PMO and California standards; milk quality test results (somatic cell count, bacteria count, antibiotics screening); equipment sanitation records per 3-A Sanitary Standards; water supply test results (bacteriological quality); cooling temperature records (within 2 hours to 45 deg F or below); PMO compliance documentation; milking system inspection records',
