UPDATE citizen_catalog SET
  governing_guidelines = 'Cal. Food & Agric. Code 35781-35799 (Milk Quality Standards); FDA Pasteurized Milk Ordinance (PMO) Appendix N (Laboratories); 21 CFR Part 133 (Cheese Standards of Identity); Interstate Milk Shippers (IMS) List and certification program; Standard Methods for the Examination of Dairy Products (SMEDP — APHA); NCIMS (National Conference on Interstate Milk Shipments) procedures',
  standards_of_creation = 'Laboratory accreditation documentation (state certification and IMS approval); test method validation records per SMEDP procedures; proficiency testing results (split sample programs); sample chain-of-custody records from collection to result; calibration records for all analytical instruments; test reports including SCC, bacteria count, antibiotic residue, fat, protein, and added water; reject and accept determinations with regulatory threshold references; analyst qualification records',
