UPDATE citizen_catalog SET
  governing_guidelines = 'Federal Meat Inspection Act, 21 USC 601-695; Poultry Products Inspection Act, 21 USC 451-472; 9 CFR Parts 300-500 (FSIS Regulations); HACCP 9 CFR Part 417 (Hazard Analysis and Critical Control Points); Cal. Food & Agric. Code 18650-18674 (Meat and Poultry Inspection — state cooperative program); Cal. Food & Agric. Code 18952 (custom slaughter inspection); FSIS Directives and Notices',
  standards_of_creation = 'FSIS grant of inspection (application and facility approval); HACCP plan with hazard analysis, critical control points, critical limits, monitoring, corrective actions, verification, and recordkeeping; Sanitation Standard Operating Procedures (SSOPs) per 9 CFR Part 416; prerequisite programs documentation; daily FSIS inspection records; product labeling approval (sketch approval or FSIS generically approved); recall and hold documentation; pathogen testing records (Salmonella, E. coli, Listeria per applicable FSIS performance standards)',
