  governing_guidelines = 'United States Warehouse Act, 7 USC 241-256; 7 CFR Part 735 (Federal Warehouse Regulations); state public warehouse licensing statutes; UCC Article 7 (Cal. Com. Code 7101-7603); Cal. Com. Code 7201 (warehouse receipt issuance requirements); Cal. Com. Code 7202 (required content of receipt); Cal. Com. Code 7204 (warehouse duty of care — reasonable care standard)',
