  governing_guidelines = '19 USC 1555-1565 (Customs Bonded Warehouses); 19 CFR Part 19 (Customs Bonded Warehouse Regulations); 19 CFR 113.63 (Customs bond conditions for bonded warehouse operators); CBP Directive 3510-004 (Bonded Warehouse Manual); Customs Modernization Act provisions; 19 USC 1592 (penalty provisions for violations)',
  standards_of_creation = 'CBP Form 301 (Customs Bond — continuous bond required); application for bonded warehouse status (Class 1-7 per 19 CFR 19.1); facility security plan meeting CBP requirements; entry and withdrawal documentation (CBP Form 7501); inventory control and recordkeeping system per 19 CFR 19.12; manipulation and manufacturing records (if applicable, Class 6 or 7); permit to transfer between bonded facilities; destruction records with CBP supervision documentation',
  soc_controls = 'CBP officer access and inspection authority at all times; continuous bond requirement with adequate surety; inventory reconciliation (periodic and annual per 19 CFR 19.12); separation of entry processing from withdrawal authorization; Automated Broker Interface (ABI) electronic filing and ACE portal integration; penalty provisions for discrepancies per 19 USC 1592; bonded warehouse operator annual self-assessment; merchandise transfer accountability between bonded locations'
WHERE name = 'Bonded Warehouse Specialist (CBP)';

