  governing_guidelines = 'United States Grain Standards Act, 7 USC 71-87k; 7 CFR Part 800 (General Grain Inspection Regulations); 7 CFR Part 868 (General Regulations under USWA); state grain dealer and warehouse licensing laws; USDA AMS Federal Grain Inspection Service (FGIS) standards; Grain Inspection, Packers and Stockyards Administration (GIPSA, now AMS) oversight',
  standards_of_creation = 'Grain elevator license (state and/or federal); official grain inspection certificates per FGIS standards; weighing certificates per FGIS procedures; grade factor analysis records (moisture, test weight, damage, foreign material); storage capacity documentation; grain quality monitoring records (temperature probes, moisture readings per bin); fumigation records (product, dosage, exposure time, aeration); grain quantity reconciliation; shrinkage calculation records per approved methodology',
