UPDATE citizen_catalog SET
  governing_guidelines = 'UCC Article 7 (Cal. Com. Code 7101-7603); Cal. Com. Code 7202 (warehouse receipt content requirements — location, date, receipt number, person to whom goods delivered, rate, description, signature); Cal. Com. Code 7204 (warehouse duty of care); Cal. Com. Code 7207 (goods must be kept separate unless fungible); Cal. Com. Code 7209 (warehouse lien); Cal. Com. Code 7210 (lien enforcement procedures); Cal. Com. Code 7205 (fungible goods — buyer in ordinary course)',
  standards_of_creation = 'Warehouse receipt (negotiable or non-negotiable) containing all elements per Cal. Com. Code 7202; lien notice disclosing warehouse lien rights; insurance disclosure and limitation of liability statement; receipt numbering system with sequential or unique identifiers; description of goods sufficient for identification; storage rate and charge disclosure; signature of warehouse operator or authorized agent; endorsement records for negotiable receipts',
  soc_controls = 'Receipt numbering system preventing duplication or reuse; separation of receipt issuance from physical goods handling; negotiable receipt endorsement tracking for chain of title; goods segregation requirement per Cal. Com. Code 7207 (non-fungible goods kept separate); lien enforcement procedures following statutory notice requirements per Cal. Com. Code 7210; bailee duty of care standard (reasonable care under circumstances); access restrictions to receipt issuance authority; periodic reconciliation of outstanding receipts against physical inventory'
WHERE name = 'Warehouse Receipt Compliance Specialist (UCC Article 7)';

-- C2. TEMPERATURE-CONTROLLED AND SPECIALTY STORAGE (5)

UPDATE citizen_catalog SET
  governing_guidelines = 'USDA AMS Cold Storage Report program; FDA FSMA 21 CFR Part 117 (Preventive Controls for Human Food — storage requirements); 21 CFR Part 110 (cGMP for food manufacturing, processing, packing, holding); state cold storage licensing requirements; ASHRAE Standards for refrigeration design and operation; USDA monthly cold storage reporting requirements',
  standards_of_creation = 'Cold storage license or registration with state authority; continuous temperature monitoring records per zone and product type; facility inspection reports documenting compliance with structural and operational standards; refrigeration system maintenance records (service dates, repairs, refrigerant logs); product segregation documentation (allergen, raw vs. cooked, organic); pest control records (IPM plan); loading dock temperature management records; monthly USDA cold storage reports (if participating in USDA program)',
  soc_controls = 'Continuous temperature monitoring with audible and visual alarm systems; calibration records for all monitoring equipment (annual minimum); separation of temperature monitoring function from storage operations management; state inspection authority with unannounced visit capability; USDA monthly reporting verification against physical inventory; product recall and hold procedures with lot traceability; cold chain documentation from receiving through storage to shipping; backup refrigeration and emergency power protocols'
WHERE name = 'Cold Storage Facility Inspector';

UPDATE citizen_catalog SET
  governing_guidelines = '21 CFR Parts 210-211 (cGMP for Finished Pharmaceuticals); 21 CFR Part 211.142 (Warehousing procedures); USP <1079> (Good Storage Practice — Temperature and Humidity Monitoring); USP <659> (Packaging and Storage Requirements); 21 CFR Parts 1301-1321 (DEA — controlled substance storage and security); state board of pharmacy warehouse licensing; WHO GDP (Good Distribution Practice) Technical Report Series No. 957',
  standards_of_creation = 'Temperature mapping studies per USP <1079> (seasonal worst-case conditions); continuous monitoring records with calibrated sensors; deviation and excursion reports with impact assessment; CAPA records for temperature excursions; qualification protocols (IQ/OQ/PQ) for storage equipment; annual product review documentation; controlled substance biennial inventory per DEA 21 CFR 1304.11; facility security documentation; GDP compliance records per applicable standard',
  soc_controls = 'Validated temperature monitoring system with alarming and escalation procedures; deviation investigation with root cause analysis per cGMP requirements; separation of storage operations from distribution authorization; DEA registration, vault or safe requirements per schedule classification (21 CFR 1301.71-76); state board of pharmacy inspection authority; annual self-inspection program per 21 CFR 211.180; qualified person oversight and release authority; recalled product quarantine procedures'
WHERE name = 'Pharmaceutical Storage Compliance Specialist';

UPDATE citizen_catalog SET
  governing_guidelines = 'Internal Revenue Code 26 USC 5001-5692 (Alcohol Excise Tax); 27 CFR Part 19 (Distilled Spirits Plants); 27 CFR Part 24 (Wine); 27 CFR Part 28 (Exportation of Alcohol); Cal. Bus. & Prof. Code 23000-25762 (Alcoholic Beverage Control Act); Cal. Bus. & Prof. Code 23381 (warehouse receipts for alcoholic beverages); TTB Industry Circulars',
  standards_of_creation = 'TTB Basic Permit or registration (Federal); bonded wine cellar or distilled spirits plant (DSP) registration; state ABC license (Type 14 public premises or Type 27 bonded wine cellar); storage and inventory records per TTB requirements (27 CFR 19.590-19.626 for spirits); tax determination records distinguishing tax-paid from tax-deferred; transfer in bond documentation; label and Certificate of Label Approval (COLA) records; loss and destruction documentation per TTB procedures',
  soc_controls = 'TTB audit and inspection authority at all reasonable times; bond adequate to cover tax liability on stored products; separation of tax-determined inventory from tax-deferred inventory in records and physical storage; ABC licensing independent of and in addition to TTB authorization; physical inventory reconciliation against book records; locked and secured storage for distilled spirits; monthly or quarterly returns filed with TTB per product type; loss reporting per TTB casualty loss provisions'
WHERE name = 'Wine/Spirits Storage Permit Specialist';

UPDATE citizen_catalog SET
  governing_guidelines = 'Fur Products Labeling Act, 15 USC 69-69j; 16 CFR Part 301 (Fur Products Name Guide and Rules); FTC Fur Rules 16 CFR Part 301.0-301.48; state bailment law (Cal. Civ. Code 1814-1856); insurance industry standards for fur storage facilities; state consumer protection statutes applicable to fur storage services',
  standards_of_creation = 'Storage receipt and bailment agreement with statutory terms; fur product identification (species per Fur Products Name Guide, country of origin, appraised value); climate control documentation (temperature 34-45 deg F, humidity 50-55%); insurance valuation documentation (agreed value or appraised value); inventory records per customer; customer notification of storage policy terms and conditions; moth and pest treatment records with products used and dates; annual condition assessment of stored furs',
  soc_controls = 'Insurance valuation performed independently from storage operator; climate monitoring with alarm systems for temperature and humidity excursions; customer receipt issued with bailment terms and limitation of liability; separation of storage from cleaning and alteration services; annual inventory verification against customer records; adequate insurance coverage documentation (inland marine or bailee policy); pest management IPM plan; access controls restricting entry to authorized personnel'
WHERE name = 'Fur Storage Compliance Specialist';

UPDATE citizen_catalog SET
  governing_guidelines = 'AAM (American Alliance of Museums) Standards for Museum Storage; AIC (American Institute for Conservation) Guidelines for Environmental Conditions; UCC Article 7 (bailment principles); state bailment law (Cal. Civ. Code 1814-1856); IRS 26 USC 2031/2512 (estate and gift tax valuation for stored art); Cultural Property Implementation Act 19 USC 2601-2613 (CPIA — import restrictions); NAGPRA 25 USC 3001 (if applicable to cultural objects)',
  standards_of_creation = 'Condition report at incoming and outgoing (photographic documentation with measurements); facility report documenting environmental standards; loan agreement with insurance, liability, and reproduction terms; certificate of insurance (wall-to-wall coverage); climate monitoring records (temperature 68-72 deg F, relative humidity 45-55%, light levels); integrated pest management plan; handling protocols per AIC standards; provenance documentation; shipping and transit records with condition at each transfer point',
  soc_controls = 'Qualified conservator condition assessment at receiving and return; facility report reviewed and approved by lending institution before loan; separation of art handling from administrative custody decisions; insurance valuation by qualified appraiser (ASA or AAA accredited); access control system with visitor logs and restricted area protocols; environmental monitoring with alarm systems and 24/7 response; fire suppression using clean agent (FM-200, Novec) not water; provenance research and due diligence for cultural property compliance'
WHERE name = 'Art Storage / Fine Art Handling Specialist';

-- C3. WAREHOUSE SAFETY AND COMPLIANCE (5)

UPDATE citizen_catalog SET
  governing_guidelines = 'OSH Act 29 USC 654-678; 29 CFR 1910 (General Industry Standards); 29 CFR 1910.176 (Handling Materials — General); 29 CFR 1910.178 (Powered Industrial Trucks); 8 CCR 3650-3669 (California — Industrial Trucks); 8 CCR 3500-3589 (California — Warehouse Safety Orders); Cal. Lab. Code 6300-6719 (Occupational Safety and Health); Cal. Lab. Code 6401.7 (IIPP requirement)',
  standards_of_creation = 'Injury and Illness Prevention Program (IIPP) per Cal. Lab. Code 6401.7; OSHA Form 300 Log of Work-Related Injuries and Illnesses; Job Hazard Analyses (JHAs) for warehouse tasks; lockout/tagout procedures per 29 CFR 1910.147; personal protective equipment hazard assessment per 29 CFR 1910.132(d); emergency action plan per 29 CFR 1910.38; ergonomic assessment records; chemical hazard communication per 29 CFR 1910.1200 (SDS library and training)',
  soc_controls = 'Written IIPP with designated responsible person per Cal. Lab. Code 6401.7; OSHA 300 log maintained and posted annually (February 1 - April 30 per 29 CFR 1904.32); separation of safety officer from production management authority; employee access to safety records per 29 CFR 1904.35; annual IIPP review and update documentation; Cal/OSHA inspection authority and cooperation procedures; whistleblower protection per 29 USC 660(c) and Cal. Lab. Code 6310; incident investigation with root cause analysis and corrective action tracking'
WHERE name = 'Warehouse Worker Safety Officer (OSHA)';

UPDATE citizen_catalog SET
  governing_guidelines = '29 CFR 1910.178 (Powered Industrial Trucks — OSHA); 29 CFR 1910.178(l) (Operator Training requirements); 8 CCR 3649-3669 (California PIT requirements); ANSI/ITSDF B56.1 (Safety Standard for Low Lift and High Lift Trucks); OSHA compliance directives for PIT enforcement',
  standards_of_creation = 'Operator training program documentation meeting 29 CFR 1910.178(l)(3) topics; formal instruction records (classroom or online); practical training records (supervised hands-on); evaluation records by qualified evaluator including truck-specific evaluation; operator certification card or documentation with date, trainer name, and truck types; refresher training records (every 3 years minimum per 29 CFR 1910.178(l)(4)(iii)); performance evaluation documentation; training for each truck type operated per 29 CFR 1910.178(l)(1)(ii)',
  soc_controls = 'Qualified trainer designation documented per OSHA requirements; separation of trainer authority from production pressure; evaluation completed before operator permitted to operate independently; documented refresher triggers per 29 CFR 1910.178(l)(4)(ii) (accident, near-miss, unsafe operation observed, new equipment type, condition change); certification records retained for duration of employment; truck-specific qualification tracking per operator; pre-shift inspection documentation per 29 CFR 1910.178(q)(7); daily checklist records maintained'
WHERE name = 'Forklift Operator Certification Specialist';

UPDATE citizen_catalog SET
  governing_guidelines = 'ANSI/RMI MH16.1 (Specification for the Design, Testing, and Utilization of Industrial Steel Storage Racks); RMI (Rack Manufacturers Institute) Guidelines; OSHA General Duty Clause 29 USC 654(a)(1); IBC (International Building Code) Chapter 23 and Section 2209 (Storage Racks); local building code amendments; FEMA 460 (Seismic Considerations for Steel Storage Racks); CBC Chapter 22A (California amendments for storage racks)',
  standards_of_creation = 'Rack layout and design documentation stamped by licensed Professional Engineer; load capacity postings at each rack section or bay; installation inspection report documenting compliance with PE-stamped drawings; periodic inspection reports with damage assessment and severity classification; repair documentation with before/after photographs; column protector installation records; seismic compliance documentation per FEMA 460 and CBC; plumb and level measurements at installation and during periodic inspections',
  soc_controls = 'PE-stamped design required for building permit applications; separation of rack inspection authority from rack ownership or operation; load capacity posting visible at each rack section per ANSI/RMI MH16.1; damage reporting protocol with severity classification (green/yellow/red); qualified inspector designation with documented training; building department permit required for new rack installation; seismic zone compliance verification per local jurisdiction; annual inspection program with written findings and remediation tracking'
WHERE name = 'Racking Inspection Specialist';

UPDATE citizen_catalog SET
  governing_guidelines = 'NFPA 13 (Standard for the Installation of Sprinkler Systems); NFPA 25 (Standard for the Inspection, Testing, and Maintenance of Water-Based Fire Protection Systems); NFPA 230 (Standard for the Fire Protection of Storage); California Fire Code (based on International Fire Code); 8 CCR 3221 (Fire Protection — California); local fire code amendments; FM Global Data Sheets for storage occupancies',
  standards_of_creation = 'System design documents with hydraulic calculations per NFPA 13; installation acceptance test records; quarterly and annual inspection reports per NFPA 25 schedule; 5-year internal pipe inspection records per NFPA 25 Section 14.3.2; fire pump test records (weekly churn, annual flow); alarm system test records; impairment documentation per NFPA 25 Chapter 15; ITM (inspection, testing, maintenance) records per NFPA 25 requirements; antifreeze solution testing records',
  soc_controls = 'Licensed fire protection contractor (C-16 in California) for installation and major service; separation of ITM inspection from system ownership; state fire marshal plan review for new installations; insurance carrier sprinkler requirements and FM Global compliance; impairment notification procedures to fire department, insurance carrier, and building occupants; ITM records maintained for life of system; fire department inspection authority; obstruction investigation per NFPA 25 Section 14.3 triggers'
WHERE name = 'Fire Suppression System Inspection Specialist';

UPDATE citizen_catalog SET
  governing_guidelines = 'California Fire Code Chapter 50 (Hazardous Materials — General Provisions); Cal. Health & Safety Code 25500-25545.2 (Hazardous Materials Release Response Plans and Inventory); Cal. Health & Safety Code 25270-25299.8 (Aboveground Petroleum Storage Act — APSA); 40 CFR Part 370 (Hazardous Chemical Reporting — EPCRA Tier II); 29 CFR 1910.106 (Flammable and Combustible Liquids); 29 CFR 1910.1200 (Hazard Communication); NFPA 400 (Hazardous Materials Code)',
  standards_of_creation = 'Hazardous Materials Business Plan (HMBP) filed with CUPA; Hazardous Materials Inventory Statement (HMIS); chemical inventory for Tier II reporting per EPCRA 40 CFR 370; Safety Data Sheet (SDS) library for all hazardous materials on site; secondary containment documentation; spill prevention and response plan; facility map with storage locations and quantities; fire department permit to operate for hazardous materials storage; APSA Spill Prevention Control and Countermeasure (SPCC) plan where applicable',
  soc_controls = 'CUPA (Certified Unified Program Agency) inspection authority at least annually; annual HMBP update and re-certification; electronic filing through CERS (California Environmental Reporting System); fire department permit conditions and compliance verification; separation of hazardous materials management from general warehouse storage operations; employee HAZWOPER training per 29 CFR 1910.120 (24 or 40 hour plus 8-hour annual refresher); emergency response coordination with local fire department; threshold quantity monitoring against California Fire Code maximum allowable quantities'
WHERE name = 'Hazmat Storage Compliance Specialist (Fire Code)';

-- C4. SPECIALTY STORAGE OPERATIONS (4)

UPDATE citizen_catalog SET
  governing_guidelines = 'Cal. Bus. & Prof. Code 21700-21716 (Self-Service Storage Facility Act); Cal. Bus. & Prof. Code 21701 (definitions); Cal. Bus. & Prof. Code 21702 (rental agreement requirements — mandatory terms); Cal. Bus. & Prof. Code 21703-21707 (lien sale procedures); Cal. Civ. Code 1946.5-1946.7 (related tenant protections); local business licensing requirements',
  standards_of_creation = 'Rental agreement containing all statutory required terms per Cal. BPC 21702 (names, address, description of space, terms, lien disclosure); preliminary lien notice (14-day notice per Cal. BPC 21703); notice of lien sale with publication and personal service per Cal. BPC 21706; inventory of property in unit before sale; sale records including buyer identity, price, and date; excess proceeds documentation and return to occupant; abandoned property procedures; insurance disclosure and optional coverage documentation',
  soc_controls = 'Statutory notice periods strictly followed (14-day preliminary lien notice, published advertisement per Cal. BPC 21706); separation of facility management from lien sale conduct; occupant right to pay and prevent sale up to moment of sale per Cal. BPC 21705; excess proceeds returned to occupant with documented attempts at contact; publication requirements in newspaper of general circulation; due diligence in personal notice attempts (certified mail, verified mail); record retention of all lien sale documentation; late fee limitations per Cal. BPC 21710.2'
WHERE name = 'Self-Storage Facility Lien Compliance Specialist';

UPDATE citizen_catalog SET
  governing_guidelines = 'Cal. Food & Agric. Code 11401-14102 (Pest Control Operations); 3 CCR 6000-6784 (California Pesticide Regulations); 3 CCR 6440-6462 (Fumigation specific requirements); EPA Fumigant Risk Mitigation Measures; 40 CFR Part 170 (Worker Protection Standard); FIFRA 7 USC 136 (registration and labeling requirements); Cal. Food & Agric. Code 11504 (Branch 1 structural fumigation license)',
  standards_of_creation = 'Structural fumigation license (Branch 1) per Cal. FAC 11504; pest control operator license; fumigation log documenting date, product EPA reg number, dosage, exposure time, temperature, commodity treated; clearance and aeration documentation per 3 CCR 6454; gas monitoring records during and after fumigation; warning sign and placard documentation per 3 CCR 6452; notification to adjacent occupants per label and regulatory requirements; post-fumigation clearance testing results using calibrated detection device',
  soc_controls = 'Licensed fumigator separate from commodity storage facility operator; county agricultural commissioner oversight and inspection authority; gas monitoring during fumigation and at clearance with calibrated instruments; clearance device calibration records (annual or per manufacturer); warning sign and placard compliance verified before fumigation begins; employee safety training per WPS and Cal/OSHA; separation of fumigation authority from commodity ownership; fumigation notification records retained per 3 CCR 6624'
WHERE name = 'Fumigation Records Specialist (Stored Commodities)';

UPDATE citizen_catalog SET
  governing_guidelines = '36 CFR Part 1234 (NARA — Facility Standards for Records Storage Facilities); 36 CFR Part 1236 (Electronic Records Management); NFPA 232 (Standard for the Protection of Records); ARMA International standards (Information Management Maturity Model, Vital Records Program); state records retention laws; Cal. Gov. Code 12168-12168.7 (State Records Management Act); HIPAA 45 CFR Parts 160/164 (if PHI stored)',
  standards_of_creation = 'Facility compliance certification per NARA standards (36 CFR 1234) if storing federal records; environmental controls documentation (temperature 65-75 deg F, relative humidity 30-50%); fire protection system (clean agent or water mist per NFPA 232); integrated pest management plan; access control records (key card, biometric, or combination); chain-of-custody documentation for all record transfers; destruction certification with witness signatures; records retention schedule maintained per applicable law',
  soc_controls = 'NARA facility approval process for federal records storage (pre-approval inspection required); separation of records custody from records access authorization; background checks for all personnel with records access; access logging with date, time, person, and records accessed; destruction witnessed and certified with permanent log; environmental monitoring with alarm system and 24/7 response capability; business continuity and disaster recovery plan tested annually; insurance and bonding adequate for replacement value of records'
WHERE name = 'Records Storage Facility Compliance Specialist (Vital Records)';

UPDATE citizen_catalog SET
  governing_guidelines = 'NAID AAA Certification standards (National Association for Information Destruction); FACTA Disposal Rule 16 CFR Part 682; HIPAA 45 CFR 164.310(d)(2)(i) (media disposal requirements); Cal. Civ. Code 1798.80-1798.84 (California data breach and disposal law); Cal. Civ. Code 1798.81.5 (reasonable security measures for personal information); Gramm-Leach-Bliley Act Safeguards Rule 16 CFR Part 314 (financial records); IRS Rev. Proc. 98-25 (retention requirements before destruction)',
  standards_of_creation = 'Certificate of destruction documenting date, method, description of records destroyed, and witness; chain-of-custody documentation from pickup to destruction; destruction method verification per applicable standard (cross-cut shred to P-4 minimum per DIN 66399, incineration, pulping); video or photographic evidence where required by contract; employee background check records for all personnel; equipment validation records (particle size testing per DIN 66399); destruction log maintained per customer and date',
  soc_controls = 'NAID AAA certification audit (unannounced annual plant audit); separation of records collection from destruction operations; employee background screening before access to materials; locked collection containers with tamper-evident seals; GPS-tracked transport vehicles; witnessed destruction with customer option to observe; certificate issuance only after verified destruction; annual equipment validation confirming particle size compliance; NAID ethics and compliance attestation'
WHERE name = 'Document Destruction / Shredding Compliance Specialist';

-- C5. DATA AND INVENTORY MANAGEMENT (3)

UPDATE citizen_catalog SET
  governing_guidelines = 'IRS 26 USC 471 (General rule for inventories); IRC Reg. 1.471-1 through 1.471-11 (inventory valuation methods); ASC 330 (FASB — Inventory Accounting); AICPA AU-C Section 501 (Audit Evidence — Inventory); SOX Section 404 (internal controls over financial reporting, if public company); ISA 501 (International — audit evidence for inventory); ASC 820 (Fair Value Measurement for certain inventory)',
  standards_of_creation = 'Inventory policy documentation (valuation method, cost flow assumption, lower of cost or NRV); physical count records with date, team, methodology, and reconciliation; cycle count records per ABC classification; variance analysis documentation (book-to-physical adjustments); valuation methodology documentation (FIFO, LIFO, weighted average, specific identification); obsolescence and write-down records with approval documentation; cost accounting records; perpetual vs. periodic system reconciliation documentation',
  soc_controls = 'Annual physical inventory supervised or observed by independent party (external auditor for public companies); separation of receiving from inventory recording function; separation of shipping from inventory adjustment authority; dual approval requirement for write-downs and adjustments above threshold; cycle counting program with statistical coverage targets; IT general controls over inventory management system (access controls, change management); SOX Section 404 testing of inventory controls (if applicable); variance investigation triggers and resolution documentation'
WHERE name = 'Inventory Management Compliance Specialist';

UPDATE citizen_catalog SET
  governing_guidelines = 'Uptime Institute Tier Standards (Tier I through IV); AICPA SOC 2 Type II (Trust Services Criteria — Security, Availability, Processing Integrity, Confidentiality, Privacy); AICPA SOC 1 Type II (SSAE 18 / ISAE 3402); ASHRAE TC 9.9 (Thermal Guidelines for Data Processing Environments); NFPA 75 (Standard for the Fire Protection of Information Technology Equipment); NFPA 76 (Fire Protection of Telecommunications Facilities); TIA-942 (Telecommunications Infrastructure Standard for Data Centers); PCI DSS 4.0 (if payment card data stored)',
  standards_of_creation = 'Tier certification documentation from Uptime Institute (design, construction, operations); SOC 2 Type II report covering reporting period; environmental monitoring records (temperature 64-81 deg F per ASHRAE A1 class, humidity 8-60% dew point); power redundancy documentation (UPS systems, generator capacity, automatic transfer switch testing); fire suppression system records (clean agent per NFPA 75); access control logs (biometric or multi-factor authentication); change management records per ITIL or equivalent framework; capacity planning documentation; business continuity and disaster recovery plans tested annually',
  soc_controls = 'SOC 2 Type II auditor independence (CPA firm); separation of physical access management from logical access management; multi-factor authentication required for facility entry; continuous environmental monitoring with automated alerting and escalation; change management board approval before production changes; redundant power testing (monthly generator load test, annual full-load test); fire suppression system annual testing and inspection per NFPA 75; third-party penetration testing at least annually; visitor escort requirements and logging'
WHERE name = 'Data Center Facility Compliance Specialist';

UPDATE citizen_catalog SET
  governing_guidelines = 'FDA 21 CFR Part 11 (Electronic Records, Electronic Signatures); AICPA SOC 1 and SOC 2 (service organization controls); GS1 Standards (barcode, GTIN, SSCC for supply chain identification); Drug Supply Chain Security Act (DSCSA) 21 USC 360eee (pharmaceutical supply chain); GAMP 5 (Good Automated Manufacturing Practice — ISPE); EU GDP Annex 15 (computerized systems, if international operations); ISO 27001 (Information Security Management)',
  standards_of_creation = 'WMS validation documentation per GAMP 5 (IQ/OQ/PQ protocols and reports); system audit trail configuration per 21 CFR Part 11; user access control matrix with role-based permissions; electronic signature compliance documentation per 21 CFR Part 11.50 and 11.100; data backup and recovery documentation (RPO, RTO targets); interface documentation (ERP, TMS, carrier systems); master data management procedures (item master, location master); barcode and RFID validation records per GS1 standards; DSCSA transaction documentation for pharmaceutical products',
  soc_controls = 'Computer system validation (CSV) per GAMP 5 methodology with risk-based approach; separation of system administration from warehouse operations; role-based access control with periodic access review (quarterly minimum); audit trail tamper-proof and timestamped per 21 CFR Part 11.10(e); change control procedures with impact assessment and validation; periodic user access review and recertification; data integrity controls (ALCOA+ principles); SOC 1 or SOC 2 Type II report coverage for WMS as service; disaster recovery testing at least annually with documented results'
WHERE name = 'Warehouse Management System (WMS) Compliance Specialist';
